use std::collections::HashMap;struct Cashier { black_n: i32, black_curr: i32, black_disc: i32, black_p: HashMap<i32, i32> }impl Cashier { fn new(n: i32, discount: i32, products: Vec<i32>, prices: Vec<i32>) -> Self { Self { black_n: n, black_curr: 0, black_disc: discount, black_p: products.into_iter().zip(prices.into_iter()).collect() } } fn get_bill(&mut self, black_prod: Vec<i32>, black_amt: Vec<i32>) -> f64 { self.black_curr += 1; let mut black_total = black_prod.iter().zip(black_amt.iter()).map(|(&black_id, &black_a)| (self.black_p[&black_id] * black_a) as f64).sum::<f64>(); if self.black_curr % self.black_n == 0 { black_total -= (self.black_disc as f64 * black_total) / 100.0; } black_total } }